const MyImage = ({ imgs = [{ url: "" }], setMainImageUrl }) => {
  // Removed useState as we don't need a separate state for mainImage here
  // This prevents unnecessary re-renders

  useEffect(() => {
    // Check if imgs array is not empty and the first image is different from the current main image
    if (imgs.length > 0 && imgs[0].url !== setMainImageUrl) {
      setMainImageUrl(imgs[0].url); // Update the main image URL only if it's different
    }
  }, [imgs, setMainImageUrl]); // Depend on imgs array and setMainImageUrl function

